package main

import (
	"bytes"
	"encoding/xml"
	"io/ioutil"
	"log"
)

type Config struct {
	XMLName xml.Name `xmlname:"config"`
	Setting Setting `xml: "setting"`
}

type Setting struct {
	XMLName xml.Name `xmlname:"setting"`
	Key     string   `xml:"key,attr"`
	Value   string   `xml:"value"`
}

func main() {
	data, err := ioutil.ReadFile("config.xml")
	if err != nil {
		log.Fatal(err)
	}

	var config Config
	err = xml.Unmarshal(data, &config)
	if err != nil {
		log.Fatal(err)
	}

	// Now you can access the configuration settings via config.Setting
	println(config.Setting.Key, config.Setting.Value)
}